async (page) => {
  await page.goto('https://caniuse.com/css-grid');
  await page.waitForLoadState('networkidle');

  // Extract global usage percentage
  const usageEl = await page.locator('.caniuse-section .stats .usage');
  const usage = (await usageEl.textContent()).trim();

  // Extract earliest Chrome full support version
  const chromeRow = await page.locator('tr').filter({ hasText: 'Chrome' });
  const chromeCells = await chromeRow.locator('td').all();
  let chromeVersion = null;
  for (let i = 1; i < chromeCells.length; i++) {
    const cell = chromeCells[i];
    const className = await cell.getAttribute('class');
    if (className && className.includes('y')) {
      chromeVersion = (await cell.textContent()).trim();
      break;
    }
  }

  // Extract earliest Firefox full support version
  const firefoxRow = await page.locator('tr').filter({ hasText: 'Firefox' });
  const firefoxCells = await firefoxRow.locator('td').all();
  let firefoxVersion = null;
  for (let i = 1; i < firefoxCells.length; i++) {
    const cell = firefoxCells[i];
    const className = await cell.getAttribute('class');
    if (className && className.includes('y')) {
      firefoxVersion = (await cell.textContent()).trim();
      break;
    }
  }

  // Extract known issues count
  const knownIssuesTab = await page.locator('[data-tab="known-issues"]');
  let knownCount = 0;
  if (await knownIssuesTab.count() > 0) {
    const text = await knownIssuesTab.textContent();
    const match = text.match(/(\d+)/);
    if (match) knownCount = parseInt(match[1]);
  }

  // Take screenshot
  await page.screenshot({ path: 'eval-caniuse-grid.png', fullPage: true });

  return { usage, chromeVersion, firefoxVersion, knownCount };
}
